#include <iostream>
#include <string>

class Student {
private:
    int studentID;
    std::string name;
    std::string major;

public:
    void setDetails(int i, std::string n_val, std::string m_val) {
        studentID = i;
        name = n_val;
        major = m_val;
    }

    void displayDetails() {
        std::cout << "Student ID: " << studentID
                  << ", Name: " << name
                  << ", Major: " << major << std::endl;
    }
};

int main() {
    Student s1;
    s1.setDetails(101, "Alice Smith", "Computer Science");
    s1.displayDetails();

    Student s2;
    s2.setDetails(202, "Bob Junior", "Mechanical Engineering");
    s2.displayDetails();

    return 0;
}
